package com.flowmind.user.entity;import java.time.LocalDateTime;public class UserEntity{private Long id;private String username;private String password;private String nickname;private String role;private LocalDateTime createdAt;private LocalDateTime updatedAt;private Boolean deleted=false;public UserEntity(){}public UserEntity(Long id,String username,String password,String nickname,String role){this.id=id;this.username=username;this.password=password;this.nickname=nickname;this.role=role;this.createdAt=LocalDateTime.now();this.updatedAt=LocalDateTime.now();}public Long getId(){return id;}public void setId(Long id){this.id=id;}public String getUsername(){return username;}public void setUsername(String username){this.username=username;}public String getPassword(){return password;}public void setPassword(String password){this.password=password;}public String getNickname(){return nickname;}public void setNickname(String nickname){this.nickname=nickname;}public String getRole(){return role;}public void setRole(String role){this.role=role;}public LocalDateTime getCreatedAt(){return createdAt;}public void setCreatedAt(LocalDateTime createdAt){this.createdAt=createdAt;}public LocalDateTime getUpdatedAt(){return updatedAt;}public void setUpdatedAt(LocalDateTime updatedAt){this.updatedAt=updatedAt;}public Boolean getDeleted(){return deleted;}public void setDeleted(Boolean deleted){this.deleted=deleted;}}
